import React, { createContext, useState } from "react";
import axios from "axios";

export const AuthContext = createContext(); // export context itself

// Only one declaration of AuthProvider
const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);

  const login = async (email, password) => {
    try {
      const res = await axios.post("http://localhost:5000/api/login", { email, password });
      setUser(res.data.user);
      alert("Login successful!");
    } catch (err) {
      console.error(err);
      alert("Login failed!");
    }
  };

  const signup = async (email, password) => {
    try {
      const res = await axios.post("http://localhost:5000/api/signup", { email, password });
      setUser(res.data.user);
      alert("Signup successful!");
    } catch (err) {
      console.error(err);
      alert("Signup failed!");
    }
  };

  return (
    <AuthContext.Provider value={{ user, login, signup }}>
      {children}
    </AuthContext.Provider>
  );
};

export default AuthProvider; // default export provider
